"""Circle packing: 26 equal circles in a centered tight grid."""
import numpy as np


def construct_packing():
    n = 26
    rows, cols = 6, 5
    r = 0.5 / max(rows, cols)
    r *= 0.9999

    grid_w = 2 * r * cols
    grid_h = 2 * r * rows
    x_off = (1.0 - grid_w) / 2.0 + r
    y_off = (1.0 - grid_h) / 2.0 + r

    centers = []
    for i in range(rows):
        for j in range(cols):
            if len(centers) >= n:
                break
            centers.append([x_off + j * 2 * r, y_off + i * 2 * r])
        if len(centers) >= n:
            break

    centers = np.array(centers[:n])
    radii = np.full(n, r)
    return centers, radii, float(np.sum(radii))
# EVOLVE-BLOCK-END


def run_packing():
    return construct_packing()


if __name__ == "__main__":
    centers, radii, sum_radii = run_packing()
    print(f"Sum of radii: {sum_radii:.6f}")

